from collections import defaultdict
class Solution:
    def gridIllumination(self, n, lamps, queries):
        on = set()
        row = defaultdict(int)
        col = defaultdict(int)
        diag = defaultdict(int)
        anti = defaultdict(int)
        for r, c in lamps:
            if (r, c) in on:
                continue
            on.add((r, c))
            row[r] += 1
            col[c] += 1
            diag[r - c] += 1
            anti[r + c] += 1
        ans = []
        for qr, qc in queries:
            if row[qr] or col[qc] or diag[qr - qc] or anti[qr + qc]:
                ans.append(1)
            else:
                ans.append(0)
            for dr in (-1, 0, 1):
                for dc in (-1, 0, 1):
                    rr, cc = qr + dr, qc + dc
                    if (rr, cc) in on:
                        on.discard((rr, cc))
                        row[rr] -= 1
                        col[cc] -= 1
                        diag[rr - cc] -= 1
                        anti[rr + cc] -= 1
        return ans

