var gridIllumination = function(n, lamps, queries) {
    const on = new Set();
    const row = new Map(), col = new Map(), diag = new Map(), anti = new Map();
    const inc = (m, k) => m.set(k, (m.get(k) || 0) + 1);
    const dec = (m, k) => m.set(k, (m.get(k) || 0) - 1);
    const key = (r, c) => r + ',' + c;
    for (const [r, c] of lamps) {
        const k = key(r, c);
        if (on.has(k)) continue;
        on.add(k);
        inc(row, r); inc(col, c); inc(diag, r - c); inc(anti, r + c);
    }
    const ans = [];
    for (const [qr, qc] of queries) {
        if ((row.get(qr) || 0) > 0 || (col.get(qc) || 0) > 0 || (diag.get(qr - qc) || 0) > 0 || (anti.get(qr + qc) || 0) > 0) {
            ans.push(1);
        } else {
            ans.push(0);
        }
        for (let dr = -1; dr <= 1; dr++) {
            for (let dc = -1; dc <= 1; dc++) {
                const rr = qr + dr, cc = qc + dc;
                const k = key(rr, cc);
                if (on.has(k)) {
                    on.delete(k);
                    dec(row, rr); dec(col, cc); dec(diag, rr - cc); dec(anti, rr + cc);
                }
            }
        }
    }
    return ans;
};
